<style>
    #widget-toggle {
    display: none;
    }
    .iframe-box {
    width: 400px;
    height: 600px;
    background: #fff;
    box-shadow: 0 4px 15px rgba(0,0,0,0.3);
    border-radius: 10px;
    overflow: hidden;
    display: none;
    position: relative;
    }
    #widget-toggle:checked + label + .iframe-box {
    display: block;
    }
    #widget-toggle:checked + label {
    display: none;
    }
    .close-btn {
    position: absolute;
    top: 5px;
    right: 50px;
    cursor: pointer;
    background: #fff;
    border-radius: 50%;
    padding: 4px 8px;
    font-weight: bold;
    }
    iframe {
    width: 100%;
    height: 100%;
    border: none;
    }
    .open-btn img {
    width: 80px;
    height: 80px;
    cursor: pointer;
    }
</style>
<input type=checkbox" id="widget-toggle" />

